func solve(nums []int64) int64 {
	// Function to check if a number is prime
	isPrime := func(n int) bool {
		if n <= 1 {
			return false
		}
		if n == 2 {
			return true
		}
		if n%2 == 0 {
			return false
		}
		for i := 3; i*i <= n; i += 2 {
			if n%i == 0 {
				return false
			}
		}
		return true
	}

	sumA := int64(0)
	sumB := int64(0)

	for i, num := range nums {
		if isPrime(i) {
			sumA += num
		} else {
			sumB += num
		}
	}

	return (sumA - sumB).Abs()
}
